  "commands": [
    "read_file /etc/aide.conf",
    "write_file /etc/aide.conf email = \"secops@example.com\"",
    "run_cmd systemctl restart aide",
    "write_file /etc/cron.d/aide_notify @reboot /usr/sbin/aide --check --email secops@example.com",
    "run_cmd chmod 644 /etc/cron.d/aide_notify"
  ]
}

