  "plan_description": "Ensure AIDE is installed and configured to email scan details after each run. This involves installing the aide package, configuring /etc/aide.conf to set the email address and appropriate notification options, and adding a cron job that runs 'aide --check' and emails the output to the designated address.",
  "commands": [
    {
      "command": "dnf install -y aide"
    },
    {
      "command": "sed -i '/^MAILADDR/s/.*/MAILADDR=root@localhost/' /etc/aide.conf"
    },
    {
      "command": "echo '0 5 * * * root /usr/sbin/aide --check | /bin/mail -s \"$(hostname) - AIDE Integrity Check\" root@localhost' >> /etc/crontab"
    }
  ],
  "file_modes": {
    "/etc/aide.conf": "0640",
    "/etc/crontab": "0644"
  }
}

